```javascript
// Frog Fact Carousel
const facts = [
    "A group of frogs is called an ‘army’.",
    "The Goliath frog can weigh up to 3.3 kg.",
    "Some frogs can jump over 20 times their body length.",
    "Poison dart frogs get their toxicity from their diet.",
    "The wood frog can survive being frozen solid.",
    "Frogs absorb water through their skin, they don’t need to drink."
];
let currentIndex = 0;

const factDisplay = document.getElementById('factDisplay');
const prevBtn = document.getElementById('prevBtn');
const nextBtn = document.getElementById('nextBtn');

function showFact(index) {
    factDisplay.textContent = facts[index];
    // Add a quick fade animation
    factDisplay.style.opacity = 0;
    setTimeout(() => {
        factDisplay.style.opacity = 1;
    }, 100);
}

prevBtn.addEventListener('click', () => {
    currentIndex = (currentIndex - 1 + facts.length) % facts.length;
    showFact(currentIndex);
});

nextBtn.addEventListener('click', () => {
    currentIndex = (currentIndex + 1) % facts.length;
    showFact(currentIndex);
});

// Initialize
showFact(currentIndex);
```

